<?php
$pageTitle = 'Storyboard Builder';
$pageDescription = 'AI-assisted storyboard builder with scene cards, modal production controls, character catalog assignments, scene background selection, exports, and job tracking.';
$pageClass = 'membership-page admin-catalog-page storyboards-page storyboard-builder-page';
require __DIR__ . '/../includes/storyboard_queue_export.php';
require_once __DIR__ . '/../includes/storyboarding_system.php';
require_once __DIR__ . '/../includes/story_scene_backgrounds.php';
$project = sf_storyboard_project((int)($_GET['project_id'] ?? 1));
$projectId = (int)($project['id'] ?? 0);
$settings = sf_storyboard_settings($project);
$builderCharacters = sf_storyboard_characters($projectId);
$catalogCharacters = function_exists('sf_story_v1_characters') ? sf_story_v1_characters('active') : [];
$characters = $catalogCharacters ?: $builderCharacters;
$backgrounds = function_exists('sf_scene_backgrounds_all') ? sf_scene_backgrounds_all('active') : [];
$scenes = sf_storyboard_scenes($projectId);
$sceneBackgroundMap = function_exists('sf_scene_backgrounds_for_scenes') ? sf_scene_backgrounds_for_scenes(array_map(static fn($row)=>(int)($row['id'] ?? 0), $scenes)) : [];
$jobs = function_exists('sf_sbc_recent_jobs') ? sf_sbc_recent_jobs($projectId, 10) : [];
$jobSummary = function_exists('sf_sbq_job_summary') ? sf_sbq_job_summary($projectId) : ['total'=>0,'queued'=>0,'running'=>0,'complete'=>0,'failed'=>0,'canceled'=>0];
$gallery = function_exists('sf_sbq_reference_gallery') ? sf_sbq_reference_gallery($projectId) : [];
$returnUrl = sf_url('admin/storyboard-builder.php?project_id=' . $projectId);
$disabledAttr = sf_storyboard_ready() ? '' : ' disabled';
$backgroundDisabledAttr = function_exists('sf_scene_backgrounds_ready') && sf_scene_backgrounds_ready() ? '' : ' disabled';
$sceneCardTotal = max(1, min(30, (int)($project['scene_count'] ?? 0) ?: (count($scenes) ?: 9)));
$sceneAssignedCharacterNames = [];
if ($projectId > 0 && sf_storyboard_ready() && sf_admin_table_exists('storyboard_scene_characters') && sf_admin_table_exists('storyboard_characters')) { $sceneCharacterLinks = sf_admin_fetch_all('SELECT l.scene_id, c.character_name FROM storyboard_scene_characters l INNER JOIN storyboard_characters c ON c.id = l.character_id WHERE l.storyboard_id = ?', [$projectId]); foreach ($sceneCharacterLinks as $link) $sceneAssignedCharacterNames[(int)$link['scene_id']][] = (string)$link['character_name']; }
require __DIR__ . '/../includes/header.php';
sf_admin_shell_start('Storyboarding', 'Storyboard builder workspace', 'Manage scene cards, prompts, background selections, catalog character assignments, AI generation, exports, and production-ready shot lists.', 'storyboards');
?>
