ame) . ' '; ?></small><details class="sf-storyboard-scene-editor"><summary>Scene Actions</summary><div class="sf-storyboard-builder-scene-actions"><form class="sf-admin-form" method="post" action="<?= sf_url('api/storyboard-scene-action.php') ?>"><?= sf_csrf_field() ?><input type="hidden" name="action" value="edit_scene"><input type="hidden" name="scene_id" value="<?= $sceneId ?>"><input type="hidden" name="return_url" value="<?= sf_storyboard_h($returnUrl . '#scene-' . $sceneNumber) ?>"><label>Title<input name="scene_title" value="<?= sf_storyboard_h($scene['title']) ?>"<?= $sceneDisabled ?>></label><label>Summary<textarea rows="2" name="scene_summary"<?= $sceneDisabled ?>><?= sf_storyboard_h($scene['summary'] ?? '') ?></textarea></label><label>Scene Prompt<textarea rows="3" name="scene_prompt"<?= $sceneDisabled ?>><?= sf_storyboard_h($scene['prompt']) ?></textarea></label><label>Image Prompt<textarea rows="3" name="image_prompt"<?= $sceneDisabled ?>><?= sf_storyboard_h($scene['image_prompt'] ?? '') ?></textarea></label><label>Dialog<textarea rows="3" name="dialog_text"<?= $sceneDisabled ?>><?= sf_storyboard_h($scene['dialog'] ?? '') ?></textarea></label><label>Action Notes<textarea rows="2" name="action_notes"<?= $sceneDisabled ?>><?= sf_storyboard_h($scene['action_notes'] ?? '') ?></textarea></label><div class="sf-admin-form-grid"><label>Location<input name="location_label" value="<?= sf_storyboard_h($scene['location_label'] ?? '') ?>"<?= $sceneDisabled ?>></label><label>Time<input name="time_of_day" value="<?= sf_storyboard_h($scene['time_of_day'] ?? '') ?>"<?= $sceneDisabled ?>></label><label>Status<select name="scene_status"<?= $sceneDisabled ?>><option value="draft"<?= $currentSceneStatus==='draft'?' selected':'' ?>>Draft</option><option value="needs_review"<?= $currentSceneStatus==='needs_review'?' selected':'' ?>>Needs Review</option><option value="ready"<?= $currentSceneStatus==='ready'?' selected':'' ?>>Ready</option><option value="archived"<?= $currentSceneStatus==='archived'?' selected':'' ?>>Archived</option></select></label></div><div class="sf-admin-form-actions"><button type="submit"<?= $sceneDisabled ?>>Save Scene</button></div></form><div class="sf-storyboard-builder-subpanel"><h4>Scene Background</h4><form class="sf-admin-form" method="post" action="<?= sf_url('api/storyboard-background-action.php') ?>"><?= sf_csrf_field() ?><input type="hidden" name="action" value="assign_scene_background"><input type="hidden" name="scene_id" value="<?= $sceneId ?>"><input type="hidden" name="return_url" value="<?= sf_storyboard_h($returnUrl . '#scene-' . $sceneNumber) ?>"><label>Background<select name="background_id"<?= $sceneDisabled . $backgroundDisabledAttr ?>><option value="0">No background selected</option><?php foreach ($backgrounds as $background): $bid = (int)($background['id'] ?? 0); ?><option value="<?= $bid ?>"<?= $sceneBackground && (int)($sceneBackground['id'] ?? 0) === $bid ? ' selected' : '' ?>><?= sf_storyboard_h($background['background_name'] ?? 'Background') ?></option><?php endforeach; ?></select></label><label>Usage Notes<textarea rows="2" name="usage_notes"<?= $sceneDisabled . $backgroundDisabledAttr ?>><?= sf_storyboard_h($sceneBackground['usage_notes'] ?? '') ?></textarea></label><div class="sf-admin-form-actions"><button type="submit"<?= $sceneDisabled . $backgroundDisabledAttr ?>>Save Background</button><a href="<?= sf_url('admin/scene-backgrounds.php') ?>">Manage Backgrounds</a></div></form></div><div class="sf-storyboard-builder-subpanel"><h4>AI Rewrite</h4><form class="sf-admin-form" method="post" action="<?= sf_url('api/storyboard-scene-action.php') ?>"><?= sf_csrf_field() ?><input type="hidden" name="action" value="rewrite_scene"><input type="hidden" name="scene_id" value="<?= $sceneId ?>"><input type="hidden" name="return_url" value="<?= sf_storyboard_h($returnUrl . '#scene-' . $sceneNumber) ?>"><label>Rewrite Instruction<input name="rewrite_instruction" placeholder="Make this scene tighter, funnier, more cinematic..."<?= $sceneDisabled ?>></label><div class="sf-admin-form-actions"><button type="submit"<?= $sceneDisabled ?>>Rewrite Scene</button></div></form></div><div class="sf-storyboard-builder-subpanel"><h4>Image Actions</h4><form class="sf-admin-form" method="post" enctype="multipart/form-data" action="<?= sf_url('api/storyboard-scene-action.php') ?>"><?= sf_csrf_field() ?><input type="hidden" name="action" value="upload_image"><input type="hidden" name="scene_id" value="<?= $sceneId ?>"><input type="hidden" name="return_url" value="<?= sf_storyboard_h($returnUrl . '#scene-' . $sceneNumber) ?>"><label>Upload Replacement Image<input type="file" name="scene_image" accept="image/*"<?= $sceneDisabled ?>></label><div class="sf-admin-form-actions"><button type="submit"<?= $sceneDisabled ?>>Upload Image</button></div></form><form class="sf-admin-form" method="post" action="<?= sf_url('api/storyboard-queue.php') ?>"><?= sf_csrf_field() ?><input type="hidden" name="action" value="enqueue_scene_image"><input type="hidden" name="scene_id" value="<?= $sceneId ?>"><input type="hidden" name="return_url" value="<?= sf_storyboard_h($returnUrl . '#scene-' . $sceneNumber) ?>"><div class="sf-admin-form-actions"><button type="submit"<?= $sceneDisabled ?>>Queue Image Job</button></div></form><form class="sf-admin-form" method="post" action="<?= sf_url('api/storyboard-scene-action.php') ?>"><?= sf_csrf_field() ?><input type="hidden" name="action" value="regenerate_image"><input type="hidden" name="scene_id" value="<?= $sceneId ?>"><input type="hidden" name="return_url" value="<?= sf_storyboard_h($returnUrl . '#scene-' . $sceneNumber) ?>"><div class="sf-admin-form-actions"><button type="submit"<?= $sceneDisabled ?>>Generate Image Now</button></div></form></div><div class="sf-storyboard-builder-subpanel"><h4>Catalog Characters</h4><div class="sf-storyboard-builder-chip-actions"><?php foreach ($characters as $character): $storyCharacterId = (int)($character['id'] ?? 0); $characterName = (string)($character['character_name'] ?? $character['name'] ?? 'Character'); if ($storyCharacterId <= 0 || $characterName === '') continue; $isAssigned = in_array($characterName, $assignedNames, true); ?><form method="post" action="<?= sf_url('api/storyboard-character-action.php') ?>"><?= sf_csrf_field() ?><input type="hidden" name="action" value="<?= $isAssigned ? 'remove_scene_character' : 'assign_scene_character' ?>"><input type="hidden" name="storyboard_id" value="<?= (int)$projectId ?>"><input type="hidden" name="scene_id" value="<?= $sceneId ?>"><input type="hidden" name="story_character_id" value="<?= $storyCharacterId ?>"><input type="hidden" name="return_url" value="<?= sf_storyboard_h($returnUrl . '#scene-' . $sceneNumber) ?>"><button type="submit" class="<?= $isAssigned ? 'is-assigned' : '' ?>"<?= $sceneDisabled ?>><?= $isAssigned ? 'Remove ' : 'Add ' ?><?= sf_storyboard_h($characterName) ?></button></form><?php endforeach; ?></div></div></div></details></div></article><?php endforeach; ?></div></section>
