<dialog class="sf-story-v1-modal sf-storyboard-wide-modal" id="sf-reference-library-modal"><div class="sf-story-v1-modal-close"><form method="dialog"><button type="submit" aria-label="Close">×</button></form></div><div class="sf-story-v1-modal-body"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Characters</span><h2>Character Catalog Assignments</h2></div><a href="<?= sf_url('admin/characters.php') ?>">Open Catalog</a></div><p class="sf-admin-copy sf-storyboard-builder-reference-copy">Character editing now happens in the main Character Catalog. This builder pulls active catalog characters for scene-card assignment.</p><div class="sf-storyboard-builder-character-grid"><?php foreach ($characters as $character): $name = (string)($character['character_name'] ?? $character['name'] ?? 'Character'); $role = (string)($character['role_type'] ?? $character['role'] ?? 'Character'); $summary = (string)($character['short_bio'] ?? $character['summary'] ?? ''); $notes = (string)($character['personality_notes'] ?? $character['notes'] ?? ''); $image = (string)($character['image_path'] ?? $character['image'] ?? ''); ?><article class="sf-storyboard-character-card"><div class="sf-storyboard-thumb sf-storyboard-character-thumb" style="background-image:url('<?= sf_storyboard_h($image ? sf_asset($image) : '') ?>')"></div><div class="sf-storyboard-character-body"><span><?= sf_storyboard_h(sf_story_v1_status_label($role)) ?></span><strong><?= sf_storyboard_h($name) ?></strong><small><?= sf_storyboard_h($summary) ?></small><small><strong>Notes:</strong> <?= sf_storyboard_h($notes) ?></small><div class="sf-story-v1-mini-actions"><a href="<?= sf_url('admin/characters.php?edit=' . (int)($character['id'] ?? 0)) ?>">Edit in Catalog</a></div></div></article><?php endforeach; ?></div><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Builder Reference Gallery</span><h2>Image References</h2></div><span class="sf-admin-mini-pill"><?= count($gallery) ?> refs</span></div><div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr><th>Character</th><th>Type</th><th>Primary</th><th>Path</th><th>Created</th></tr></thead><tbody><?php foreach ($gallery as $ref): ?><tr><td><strong><?= sf_storyboard_h($ref['character_name']) ?></strong><small><?= sf_storyboard_h($ref['role_label'] ?? '') ?></small></td><td><?= sf_storyboard_h($ref['reference_type']) ?></td><td><?= !empty($ref['is_primary']) ? 'Yes' : 'No' ?></td><td><?= sf_storyboard_h($ref['media_path'] ?? $ref['reference_path'] ?? '') ?></td><td><?= sf_storyboard_h($ref['created_at'] ?? '') ?></td></tr><?php endforeach; ?><?php if (!$gallery): ?><tr><td colspan="5">No builder references uploaded yet.</td></tr><?php endif; ?></tbody></table></div></div></dialog>
